func (r *OrderRepo) EnrichItems(ctx context.Context, orders []Order) error {
    ids := make([]int64, len(orders))
    for i, o := range orders { ids[i] = o.ID }
    rows, err := r.db.QueryContext(ctx, getItemsSQL, pq.Array(ids)) // GOOD: single query
    return err
